// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXE 200005
int N, E;
int in[MAXN], out[MAXN];
int edge[MAXE][2];
int ans[MAXE][2];
void dfs(int u) {
    while (in[u] < out[u]) {
        int v = edge[in[u]][1];
        in[u]++;
        dfs(v);
    }
}
int main() {
    scanf("%d %d", &N, &E);
    for (int i = 0; i < E; i++) {
        scanf("%d %d", &edge[i][0], &edge[i][1]);
        out[edge[i][0]]++;
        in[edge[i][1]]++;
    }
    int start = 0;
    for (int i = 1; i <= N; i++) {
        if (out[i] - in[i] == 1) {
            start = i;
            break;
        }
    }
    if (start == 0) {
        printf("NO\n");
        return 0;
    }
    dfs(start);
    printf("YES\n");
    for (int i = 0; i < E; i++) {
        printf("%d %d\n", ans[i][0], ans[i][1]);
    }
    return 0;
}

