// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    static final int MAXN = 100005;
    static final int MAXE = 200005;
    static int N, E;
    static int[] in = new int[MAXN];
    static int[] out = new int[MAXN];
    static int[][] edge = new int[MAXE][2];
    static int[][] ans = new int[MAXE][2];
    public static void dfs(int u) {
        while (in[u] < out[u]) {
            int v = edge[in[u]][1];
            in[u]++;
            dfs(v);
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        E = sc.nextInt();
        for (int i = 0; i < E; i++) {
            edge[i][0] = sc.nextInt();
            edge[i][1] = sc.nextInt();
            out[edge[i][0]]++;
            in[edge[i][1]]++;
        }
        int start = 0;
        for (int i = 1; i <= N; i++) {
            if (out[i] - in[i] == 1) {
                start = i;
                break;
            }
        }
        if (start == 0) {
            System.out.println("NO");
            return;
        }
        dfs(start);
        System.out.println("YES");
        for (int i = 0; i < E; i++) {
            System.out.println(edge[i][0] + " " + edge[i][1]);
        }
    }
}

